  no Photo
  everyPhotoPostedByOneUser
} for 4 expect 1

run {
  one u : User
  one p : Photo
  u.posts = p
  everyPhotoPostedByOneUser
} for 4 expect 1

run {
  #Photo = 2
  one u : User
  u.posts = Photo
  everyPhotoPostedByOneUser
} for 4 expect 1

run {
  some p : Photo {
    not (some u : User | p in u.posts)
  }
  everyPhotoPostedByOneUser
} for 4 expect 0

run {
  some p : Photo {
    some u1, u2 : User | u1 != u2 and p in u1.posts and p in u2.posts
  }
  everyPhotoPostedByOneUser
} for 4 expect 0

run {
  #Photo = 2
  #User = 2
  distinct p1, p2 : Photo
  distinct u1, u2 : User
  // p1 is unposted
  no u : User | p1 in u.posts
  // p2 is multiply posted
  p2 in u1.posts and p2 in u2.posts
  everyPhotoPostedByOneUser
} for 4 expect 0

