parse:
run {
  no u : User, a : Ad | a in u.posts
  Req
} for 4 expect 1

run {
  some u1, u2 : User, a1, a2 : Ad, p3, p4 : Photo - Ad | {
    u1 != u2
    a1 != a2
    p3 != p4
    u1.posts = a1 + a2
    u2.posts = p3 + p4
  }
  Req
} for 4 expect 1

run {
  some u1, u2 : User, a1 : Ad | {
    u1 != u2
    u1.posts = a1
    u2.posts = none
  }
  Req
} for 4 expect 1

run {
  no User
  Req
} for 4 expect 1

run {
  some User // Ensure at least one user exists
  all u : User | u.posts = none // All users have empty posts set
  Req
} for 4 expect 1

run {
  some u1 : User, a1 : Ad, p1 : Photo - Ad | {
    u1.posts = a1 + p1
  }
  Req
} for 4 expect 0

run {
  some u1, u2 : User, a1 : Ad, p1 : Photo - Ad, p2 : Photo - Ad | {
    u1 != u2
    p1 != p2
    u1.posts = a1 + p1 // Violating user
    u2.posts = p2      // Non-violating user
  }
  Req
} for 4 expect 0

run {
  some u1 : User, a1, a2 : Ad, p1 : Photo - Ad | {
    a1 != a2
    u1.posts = a1 + a2 + p1
  }
  Req
} for 4 expect 0

run {
  some i1 : Influencer, a1 : Ad, p1 : Photo - Ad | {
    i1.posts = a1 + p1
  }
  Req
} for 4 expect 0

run {
  some u1 : User, a1 : Ad, p1, p2 : Photo - Ad | {
    p1 != p2
    u1.posts = a1 + p1 + p2
  }
  Req
} for 4 expect 0

run Positive_NoInfluencers {
  no Influencer
  InfluencersFollowedByEveryoneElse
} for 4 expect 1

run Positive_OneInfluencerNoOtherUsers {
  #User = 1
  one u: User {
    u in Influencer
  }
  InfluencersFollowedByEveryoneElse
} for 4 expect 1

run Positive_OneInfluencerAllOthersFollow {
  one i: Influencer
  some (User - i) // Ensure there's at least one user who is not the influencer
  all u: (User - i) | i in u.follows // All other users follow the influencer
  InfluencersFollowedByEveryoneElse
} for 4 expect 1

run Positive_TwoInfluencersAllFollowEachOther {
  #Influencer = 2
  no (User - Influencer) // All users are influencers
  all disj i1, i2: Influencer {
    i1 in i2.follows and i2 in i1.follows
  }
  InfluencersFollowedByEveryoneElse
} for 4 expect 1

run Positive_MultipleInfluencersAllOthersFollow {
  #Influencer = 2
  #User - Influencer = 1 // Two influencers, one non-influencer user
  all i: Influencer, u: User | u != i implies i in u.follows
  InfluencersFollowedByEveryoneElse
} for 4 expect 1

run Negative_NonInfluencerDoesNotFollow {
  one i: Influencer
  one u: User - Influencer { // A user who is not an influencer
    not (i in u.follows)     // This user does not follow the influencer
  }
  InfluencersFollowedByEveryoneElse
} for 4 expect 0

run Negative_InfluencerDoesNotFollowAnotherInfluencer {
  some disj i1, i2: Influencer { // At least two distinct influencers
    not (i1 in i2.follows)      // One influencer does not follow the other (i2 doesn't follow i1)
  }
  InfluencersFollowedByEveryoneElse
} for 4 expect 0

run Negative_OneInfluencerOneOfManyDoesNotFollow {
  one i: Influencer
  some disj u1, u2: User - i { // Two distinct users, neither is the influencer
    not (i in u1.follows)       // One of them does not follow the influencer
    // i in u2.follows             // This isn't strictly necessary for a negative case, but highlights partial adherence
  }
  InfluencersFollowedByEveryoneElse
} for 4 expect 0

run Negative_InfluencerAndNonInfluencerFailures {
  some disj i1, i2: Influencer
  one u: User - Influencer { // One non-influencer user
    not (i1 in u.follows)     // This user does not follow i1
  }
  InfluencersFollowedByEveryoneElse
} for 4 expect 0

run Negative_DirectNegation {
  some i: Influencer, u: User | u != i and not (i in u.follows) // Directly models the negation of the predicate
  InfluencersFollowedByEveryoneElse
} for 4 expect 0

run InfluencersPostEveryDay {
  one i : Influencer
  one d : Day
  one p : Photo | p.date = d and p in i.posts
} for 4 expect 1

run InfluencersPostEveryDay {
  one i : Influencer
  some d1, d2 : Day | d1 != d2
  some p1 : Photo | p1.date = d1 and p1 in i.posts
  some p2 : Photo | p2.date = d2 and p2 in i.posts
} for 4 expect 1

run InfluencersPostEveryDay {
  some i1, i2 : Influencer | i1 != i2
  one d : Day
  some p1 : Photo | p1.date = d and p1 in i1.posts
  some p2 : Photo | p2.date = d and p2 in i2.posts
} for 4 expect 1

run InfluencersPostEveryDay {
  one i : Influencer
  one d : Day
  no i.posts
} for 4 expect 0

run InfluencersPostEveryDay {
  one i : Influencer
  some d_posted, d_missed : Day | d_posted != d_missed
  some p : Photo | p.date = d_posted and p in i.posts
  no p_on_d_missed : i.posts | p_on_d_missed.date = d_missed // 'i' has no post on 'd_missed'
} for 4 expect 0

run InfluencersPostEveryDay {
  some i1, i2 : Influencer | i1 != i2
  one d : Day
  some p1 : Photo | p1.date = d and p1 in i1.posts
  no p_on_d_by_i2 : i2.posts | p_on_d_by_i2.date = d // 'i2' doesn't post on 'd'
} for 4 expect 0

run InfluencersPostEveryDay {
  one i : Influencer
  one d_target : Day
  some d_other : Day | d_other != d_target
  // This fact states that all posts by 'i' are on 'd_other'.
  // Thus, 'i' cannot have posted on 'd_target'.
  i.posts.date = d_other
} for 4 expect 0

valid:
run {
  #User = 3
  some disj u0, u1, u2 : User {
    u0.follows = u1 + u2 // u0 follows u1 AND u2
    u1.follows = u2      // u1 follows u2

    // Assert an incorrect suggestion: u2 is already followed by u0, so should NOT be in u0.suggested
    u0.suggested = u2

    // Ensure other suggested sets are as expected (should be none based on the general rule for others)
    u1.suggested = none
    u2.suggested = none
    all u : User - (u0 + u1 + u2) | u.follows = none and u.suggested = none
  }
} for 4 expect 1

run {
  #User = 3
  some disj u0, u1, u2 : User {
    u0.follows = u1
    u1.follows = none // u1 follows nobody
    u2 not in u0.follows // u0 doesn't follow u2

    // Assert an incorrect suggestion: u2 is not in u0.follows.follows, so should NOT be in u0.suggested
    u0.suggested = u2

    // Ensure other suggested sets are as expected
    u1.suggested = none
    u2.suggested = none
    all u : User - (u0 + u1 + u2) | u.follows = none and u.suggested = none
  }
} for 4 expect 1

run {
  #User = 3
  some disj u0, u1, u2 : User {
    u0.follows = u1
    u1.follows = u2
    u2 not in u0.follows // u2 meets criteria for u0 (u2 is followed by u1, u1 is followed by u0, u2 not followed by u0)

    // Assert an incorrect suggestion: u2 SHOULD be in u0.suggested, but isn't (u0.suggested is empty)
    u0.suggested = none

    // Ensure other suggested sets are as expected
    u1.suggested = none
    u2.suggested = none
    all u : User - (u0 + u1 + u2) | u.follows = none and u.suggested = none
  }
} for 4 expect 1

run {
  #User = 1 // Only one user needed for this scenario
  one u0 : User {
    u0.follows = none

    // Assert an incorrect suggestion: a user cannot suggest themselves
    u0.suggested = u0
  }
} for 4 expect 1

run {
  #User = 2
  some disj u0, u1 : User {
    u0.follows = none // u0 follows nobody, so u0.follows.follows is also empty

    // Assert an incorrect suggestion: u0 should have no suggestions if they follow no one
    u0.suggested = u1

    // Ensure other suggested sets are as expected
    u1.suggested = none
    all u : User - (u0 + u1) | u.follows = none and u.suggested = none
  }
} for 4 expect 1

parse:
run {
  no Ad.sees and // No Ad is seen by any user
  userOnlySeesAdsFromFollowedOrSuggested
} for 4 expect 1

run {
  (some u1, u2 : User, a1 : Ad | (
    u1 != u2 and
    a1 in u2.posts and      // u2 posts a1
    u2 in u1.follows and    // u1 follows u2
    a1 in u1.sees          // u1 sees a1
  )) and userOnlySeesAdsFromFollowedOrSuggested
} for 4 expect 1

run {
  (some u1, u2 : User, a1 : Ad | (
    u1 != u2 and
    a1 in u2.posts and      // u2 posts a1
    u2 in u1.suggested and  // u2 is suggested to u1
    a1 in u1.sees          // u1 sees a1
  )) and userOnlySeesAdsFromFollowedOrSuggested
} for 4 expect 1

run {
  (some u1, u_poster : User, a1 : Ad | (
    u1 != u_poster and
    a1 in u_poster.posts and
    a1 in u1.sees and
    not (u_poster in u1.follows or u_poster in u1.suggested)
  )) and userOnlySeesAdsFromFollowedOrSuggested
} for 4 expect 0

run {
  (some u1, u_followed, u_suggested, u_violator_poster : User, a_violating : Ad | (
    u_violator_poster != u1 and

    u_followed in u1.follows and
    u_suggested in u1.suggested and

    a_violating in u_violator_poster.posts and
    a_violating in u1.sees and
    not (u_violator_poster in u1.follows or u_violator_poster in u1.suggested)
  )) and userOnlySeesAdsFromFollowedOrSuggested
} for 4 expect 0

run {
  (some u1 : User, a1 : Ad | (
    a1 in u1.sees and
    no u_poster : User | a1 in u_poster.posts // a1 is not posted by anyone
  )) and userOnlySeesAdsFromFollowedOrSuggested
} for 4 expect 0

run {
  (some u1 : User, inf : Influencer, a1 : Ad | (
    u1 != inf and
    a1 in inf.posts and
    a1 in u1.sees and
    not (inf in u1.follows or inf in u1.suggested)
  )) and userOnlySeesAdsFromFollowedOrSuggested
} for 4 expect 0

run {
  (some u1 : User, a1 : Ad | (
    a1 in u1.posts and // u1 posts a1
    a1 in u1.sees and  // u1 sees a1 (their own ad)
    not (u1 in u1.follows or u1 in u1.suggested)
  )) and userOnlySeesAdsFromFollowedOrSuggested
} for 4 expect 0

