consistent:
run {
  (some c: Component, w: Workstation |
    no c.parts and // Violation: A component instance has no parts
    c.workstation = w) // Ensure c has a workstation for valid Component instance
  // Requirement: Components must have parts AND Materials have no parts
  and ((all c_comp: Component | some c_comp.parts) and (all m_mat: Material | no m_mat.parts))
} for 4 expect 0

run {
  (some m: Material, p: Product |
    m.parts = p) // Violation: A material instance has parts
  // Requirement: Components must have parts AND Materials have no parts
  and ((all c_comp: Component | some c_comp.parts) and (all m_mat: Material | no m_mat.parts))
} for 4 expect 0

run {
  (some c1, c2: Component, p: Product, w1, w2: Workstation |
    c1.parts = p and // c1 has parts (satisfies for c1)
    c1.workstation = w1 and
    no c2.parts and   // c2 does not have parts (violates for c2, thus for all components)
    c2.workstation = w2)
  // Requirement: Components must have parts AND Materials have no parts
  and ((all c_comp: Component | some c_comp.parts) and (all m_mat: Material | no m_mat.parts))
} for 4 expect 0

run {
  (some m1, m2: Material, p: Product |
    no m1.parts and   // m1 has no parts (satisfies for m1)
    m2.parts = p)  // m2 has parts (violates for m2, thus for all materials)
  // Requirement: Components must have parts AND Materials have no parts
  and ((all c_comp: Component | some c_comp.parts) and (all m_mat: Material | no m_mat.parts))
} for 4 expect 0

run {
  (some c: Component, w: Workstation |
    no c.parts and                 // Violation 1: A component has no parts
    c.workstation = w)
  and
  (some m: Material, p: Product |
    m.parts = p)                // Violation 2: A material has parts
  // Requirement: Components must have parts AND Materials have no parts
  and ((all c_comp: Component | some c_comp.parts) and (all m_mat: Material | no m_mat.parts))
} for 4 expect 0

