run {
  no Workstation
  humansAndRobotsCannotWorkTogether
} for 4 expect 1

run {
  some w : Workstation
  some h : Human
  all w_ : Workstation | w_.workers in Human
  humansAndRobotsCannotWorkTogether
} for 4 expect 1

run {
  some w : Workstation
  some r : Robot
  all w_ : Workstation | w_.workers in Robot
  humansAndRobotsCannotWorkTogether
} for 4 expect 1

run {
  some h : Human, r : Robot
  some w_human_only, w_robot_only : Workstation {
    w_human_only != w_robot_only
  }
  h in w_human_only.workers
  no (w_human_only.workers & Robot) // Explicitly no robots in human-only workstation
  r in w_robot_only.workers
  no (w_robot_only.workers & Human) // Explicitly no humans in robot-only workstation
  humansAndRobotsCannotWorkTogether
} for 4 expect 1

run {
  some Workstation
  all w : Workstation | no w.workers
  humansAndRobotsCannotWorkTogether
} for 4 expect 1

run {
  one w : Workstation {
    some h : Human, r : Robot
    h in w.workers
    r in w.workers
  }
  humansAndRobotsCannotWorkTogether
} for 4 expect 0

run {
  some Workstation
  some h_global : Human, r_global : Robot // Ensure global availability of types
  all w : Workstation {
    some h_w : Human, r_w : Robot // Each workstation gets a pair
    h_w in w.workers
    r_w in w.workers
  }
  humansAndRobotsCannotWorkTogether
} for 4 expect 0

run {
  some h : Human, r : Robot, w : Workstation {
    h in w.workers
    r in w.workers
  }
  humansAndRobotsCannotWorkTogether
} for 4 expect 0

run {
  some w_violating, w_human_only, w_robot_only, w_empty : Workstation {
    w_violating != w_human_only and w_violating != w_robot_only and w_violating != w_empty
    w_human_only != w_robot_only and w_human_only != w_empty
    w_robot_only != w_empty
  }

  some h1, h2 : Human
  some r1, r2 : Robot

  // Violating workstation
  h1 in w_violating.workers
  r1 in w_violating.workers

  // Human-only workstation
  h2 in w_human_only.workers
  no (w_human_only.workers & Robot)

  // Robot-only workstation
  r2 in w_robot_only.workers
  no (w_robot_only.workers & Human)

  // Empty workstation
  no w_empty.workers

  humansAndRobotsCannotWorkTogether
} for 4 expect 0

run {
  one c: Component
  no c.parts
} for 4 expect 1

run {
