  }
  component_danger_propagation
} for 4 expect 1

run {
  one c: Component, w: Workstation, m: Material {
    c.workstation = w
    c.parts = m
    m not in Dangerous
    c not in Dangerous // 'false implies false' is true. Could also be 'c in Dangerous' ('false implies true' is true).
  }
  component_danger_propagation
} for 4 expect 1

run {
  one c1, c2: Component, w1, w2: Workstation, m: Material {
    c1.workstation = w1
    c2.workstation = w2
    c1.parts = m
    m in Dangerous
    c1 in Dangerous // c1 is dangerous, thus a dangerous part for c2
    c2.parts = c1
    c2 in Dangerous // c2 is dangerous because it contains dangerous part c1
  }
  component_danger_propagation
} for 4 expect 1

run {
  one c1, c2: Component, w1, w2: Workstation, m: Material {
    c1.workstation = w1
    c2.workstation = w2
    c1.parts = m
    m in Dangerous
    c1 in Dangerous // c1 follows the rule (premise true, conclusion true)
    c2.parts = none // c2 has no parts, so the implication's premise is false for c2
    c2 not in Dangerous
  }
  component_danger_propagation
} for 4 expect 1

run {
  one c: Component, w: Workstation, m1, m2: Material {
    c.workstation = w
    c.parts = m1 + m2
    m1 in Dangerous
    m2 not in Dangerous
    c in Dangerous // c is dangerous because it contains dangerous part m1
  }
  component_danger_propagation
} for 4 expect 1

run {
  one c: Component, w: Workstation, m: Material {
    c.workstation = w
    c.parts = m
    m in Dangerous
    c not in Dangerous // VIOLATION: 'c' has a dangerous part (m) but is not dangerous
  }
  component_danger_propagation
} for 4 expect 0

run {
  one c1, c2: Component, w1, w2: Workstation, m: Material {
    c1.workstation = w1
    c2.workstation = w2
    c1.parts = m
    m in Dangerous
    c1 in Dangerous // c1 is dangerous, making it a dangerous part for c2
    c2.parts = c1
    c2 not in Dangerous // VIOLATION: 'c2' has a dangerous part (c1) but is not dangerous
  }
  component_danger_propagation
} for 4 expect 0

run {
  one c: Component, w: Workstation, m1, m2: Material {
    c.workstation = w
    c.parts = m1 + m2
    m1 in Dangerous
    m2 not in Dangerous
    c not in Dangerous // VIOLATION: 'c' has a dangerous part (m1) but is not dangerous
  }
  component_danger_propagation
} for 4 expect 0

run {
  one c: Component, w: Workstation, m: Material {
    c.workstation = w
    c.parts = m
    m in Dangerous
    c not in Dangerous // VIOLATION
    // Ensure sufficient atoms, potentially another non-violating component doesn't prevent finding this violation.
    one c_ok: Component {
        c_ok.parts = none // Does not violate
        c_ok not in Dangerous
    }
  }
  component_danger_propagation
} for 4 expect 0

run {
  one c_outer, c_inner: Component, w_outer, w_inner: Workstation, m_base: Material {
    c_outer.workstation = w_outer
    c_inner.workstation = w_inner
    m_base in Dangerous

    // c_inner has a dangerous part (m_base), but c_inner itself is NOT dangerous. This is the violation.
    c_inner.parts = m_base
    c_inner not in Dangerous

    // c_outer has c_inner as a part. Since c_inner is not dangerous, c_outer's premise
    // "some p: c_outer.parts | p in Dangerous" would be false, thus c_outer itself does not violate.
    // However, the overall instance contains a violation (from c_inner).
    c_outer.parts = c_inner
    c_outer not in Dangerous // Or in Dangerous; it does not change the fact that c_inner violates.
  }
  component_danger_propagation
} for 4 expect 0

