parse:
run Positive_1_StandardLine {
    // Defines a single line: begin -> w1 -> w2 -> end
    some disj w1, w2: Workstation - begin - end {
        succ = (begin -> w1) + (w1 -> w2) + (w2 -> end)
    } and isLine(begin, end)
} for 4 Workstation expect 1

run Positive_2_ExplicitSuccessorDefinition {
    // Another instance of the standard line, emphasizing the definition of succ
    some disj ws_a, ws_b: Workstation - begin - end {
        succ = (begin -> ws_a) + (ws_a -> ws_b) + (ws_b -> end)
        no end.succ // Explicitly state no successor for 'end' (redundant but harmless given the predicate)
    } and isLine(begin, end)
} for 4 Workstation expect 1

