run P2_OneStudentOneCourse_Compliant {
  // Positive Instance 2: One student, one course, one grade. Student is enrolled and has a grade in it.
  one s : Student, c : Course, g : Grade
  s->g in c.grades
  c in s.enrolled

  // The requirement being tested: Students only have grades in courses they are enrolled.
  all s_check : Student, c_check : Course | s_check in c_check.grades.Person implies c_check in s_check.enrolled
} for 4 expect 1

run P3_MultiStudentsMultiCourses_AllCompliant {
  // Positive Instance 3: Two students, two courses, two grades. All are compliant.
  some disj s1, s2 : Student, disj c1, c2 : Course, disj g1, g2 : Grade

  s1->g1 in c1.grades
  c1 in s1.enrolled

  s2->g2 in c2.grades
  c2 in s2.enrolled

  // Ensure no other grades exist between these students/courses
  no (s1.(c2.grades))
  no (s2.(c1.grades))

  // Ensure enrollments are only as specified for simplicity
  no (s1.enrolled - c1)
  no (s2.enrolled - c2)

  // The requirement being tested: Students only have grades in courses they are enrolled.
  all s_check : Student, c_check : Course | s_check in c_check.grades.Person implies c_check in s_check.enrolled
} for 4 expect 1

run P4_StudentsEnrolledAndGradedOnlyInThose {
  // Positive Instance 4: One student, two courses. Enrolled in C1 and has a grade. Not enrolled in C2 and has no grade.
  one s : Student, g : Grade
  some disj c1, c2 : Course

  s->g in c1.grades
  c1 in s.enrolled

  no (s.(c2.grades)) // Student has no grade in c2
  not (c2 in s.enrolled) // Student is not enrolled in c2

  // The requirement being tested: Students only have grades in courses they are enrolled.
  all s_check : Student, c_check : Course | s_check in c_check.grades.Person implies c_check in s_check.enrolled
} for 4 expect 1

run P5_ProfessorsHaveGradesButStudentsComply {
  // Positive Instance 5: A professor has a grade (allowed). Students are compliant.
  one s : Student, p : Professor, g1, g2 : Grade
  some disj c1, c2 : Course

  p->g1 in c1.grades // Professor has a grade, which is irrelevant to the student requirement

  s->g2 in c2.grades // Student s has a grade in c2
  c2 in s.enrolled   // Student s is enrolled in c2

  no (s.(c1.grades)) // Ensure student s has no grades in c1

  // The requirement being tested: Students only have grades in courses they are enrolled.
  all s_check : Student, c_check : Course | s_check in c_check.grades.Person implies c_check in s_check.enrolled
} for 4 expect 1

run N1_StudentGradedNotInEnrolled {
  // Negative Instance 1: One student has a grade in a course but is NOT enrolled in it.
  one s : Student, c : Course, g : Grade

  s->g in c.grades       // s has a grade in c
  not (c in s.enrolled)  // s is NOT enrolled in c -- This is the violation condition

  // The requirement being tested.
  all s_check : Student, c_check : Course | s_check in c_check.grades.Person implies c_check in s_check.enrolled
} for 4 expect 0

run N2_StudentPartiallyViolates {
  // Negative Instance 2: One student violates for one course, but complies for another.
  one s : Student, disj c1, c2 : Course, disj g1, g2 : Grade

  // Violation for c1
  s->g1 in c1.grades
  not (c1 in s.enrolled)

  // Compliance for c2
  s->g2 in c2.grades
  c2 in s.enrolled

  // The requirement being tested.
  all s_check : Student, c_check : Course | s_check in c_check.grades.Person implies c_check in s_check.enrolled
} for 4 expect 0

run N3_MultiStudentOneViolation {
  // Negative Instance 3: Multiple students exist, but only one violates the rule.
  some disj s_violator, s_compliant : Student
  some disj c_violating, c_compliant : Course
  some disj g1, g2 : Grade

  // s_violator has a grade in c_violating but is not enrolled
  s_violator->g1 in c_violating.grades
  not (c_violating in s_violator.enrolled)

  // s_compliant has a grade in c_compliant and is enrolled
  s_compliant->g2 in c_compliant.grades
  c_compliant in s_compliant.enrolled

  // Ensure no other grades for simplicity
  no (Course.grades - (s_violator->g1) - (s_compliant->g2))

  // The requirement being tested.
  all s_check : Student, c_check : Course | s_check in c_check.grades.Person implies c_check in s_check.enrolled
} for 4 expect 0

run N4_StudentViolatesInMultipleCourses {
  // Negative Instance 4: One student violates the rule for multiple courses.
