run N5_ProfessorAndStudentViolation {
  // Negative Instance 5: A professor has a grade (irrelevant), but a student still violates the requirement.
  one s : Student, p : Professor, g_prof : Grade, g_student : Grade
  some disj c_prof, c_student : Course

  // Professor p has a grade in c_prof (irrelevant to the student requirement)
  p->g_prof in c_prof.grades

  // Student s violates in c_student
  s->g_student in c_student.grades
  not (c_student in s.enrolled)

  // The requirement being tested.
  all s_check : Student, c_check : Course | s_check in c_check.grades.Person implies c_check in s_check.enrolled
} for 4 expect 0

