run {
  some disj sA, sB, sC : Student // Three distinct students
  some disj pX, pY, pZ, pW : Project { // Four distinct projects
    sA.projects = pX + pY // sA works on pX, pY
    sB.projects = pX + pZ // sB works on pX, pZ (shares pX with sA)
    sC.projects = pY + pW // sC works on pY, pW (shares pY with sA)
    // (sB.projects & sC.projects) is empty
    // All pairs share at most one project:
    // sA,sB share {pX} (count=1)
    // sA,sC share {pY} (count=1)
    // sB,sC share {} (count=0)
  }
  check_no_same_students_in_diff_projects
} for 4 expect 1

