    some disj pA, pB : Project { // At least two distinct projects
      s1.projects = pA + pB // s1 works on pA and pB
      s2.projects = pA + pB // s2 also works on pA and pB
      // Thus, s1 and s2 share {pA, pB}, which has a count of 2.
    }
  }
  check_no_same_students_in_diff_projects
